import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../core/services/auth.service';
import { Role } from '../core/models';

interface NavItem {
  label: string;
  path: string;
  icon: string;
  roles?: Role[];
}

@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent {
  private readonly nav: NavItem[] = [
    { label: 'Dashboard', path: '/dashboard', icon: '▤' },
    { label: 'Customers', path: '/customers', icon: '👥', roles: ['sales', 'admin'] },
    { label: 'Sales Orders', path: '/sales-orders', icon: '🧾', roles: ['sales', 'admin'] },
    { label: 'Invoices', path: '/invoices', icon: '💳', roles: ['sales', 'admin'] },
    { label: 'Suppliers', path: '/suppliers', icon: '🏭', roles: ['purchasing', 'admin'] },
    { label: 'Purchase Orders', path: '/purchase-orders', icon: '📦', roles: ['purchasing', 'admin'] },
    { label: 'Products', path: '/products', icon: '🧱' },
    { label: 'Users', path: '/users', icon: '🛡️', roles: ['admin'] },
    { label: 'Admin Settings', path: '/admin/settings', icon: '⚙️', roles: ['admin'] },
  ];

  sidebarOpen = signal(false);

  readonly visibleNav = computed<NavItem[]>(() =>
    this.nav.filter((n) => !n.roles || this.auth.hasRole(...n.roles)),
  );
  readonly tabNav = computed<NavItem[]>(() => this.visibleNav().slice(0, 4));

  readonly user = this.auth.user;
  readonly role = this.auth.role;

  constructor(private auth: AuthService) {}

  initials(): string {
    const email = this.user()?.email ?? '';
    return email.slice(0, 2).toUpperCase() || 'ME';
  }

  toggleSidebar(): void {
    this.sidebarOpen.update((v) => !v);
  }

  closeSidebar(): void {
    this.sidebarOpen.set(false);
  }

  logout(): void {
    this.auth.logout();
  }
}
